
import math

log = open("./filterloggl.txt","w")

def convertToPts(s):
    pts = []
    ss = s.split(" ")
    for i in ss:
        dim3= i.split(",")
        dim3[0] = float(dim3[0])
        dim3[1] = float(dim3[1])
        dim3[2] = float(dim3[2])
        pts.append(dim3)
    return pts


def convertToStr(pts):
    # s=""
    # for p in pts:
    #     s+=str(p[0]) + ","
    #     s += str(p[1]) + ","
    #     s += str(p[2]) + " "
    # s= s[:len(s)-1]
    # return s
    s = "INSERT INTO traj_table(traj) VALUES ('LINESTRINGM("
    for p in pts:
        s += str(p[0]) + " "
        s += str(p[1]) + " "
        s += str(p[2]) + ","
    s = s[:- 1]+")'::geometry);"
    return s


def filter(pts):
    res = []
    for i in range(len(pts)):
        lb = i
        hb = i
        for j in range(10):
            if(i-j-1>=0 and pts[i-j][2] - pts[i-j-1][2] <= 600):
                lb-=1
            if (i + j + 1 <len(pts) and pts[i + j+1][2] - pts[i + j ][2] <= 600):
                hb += 1
        rlen = hb - lb
        if rlen < 5:
            res.append(pts[i])
            continue
        realm = pts[lb:i]+pts [i+1:hb+1]
        sumx= 0
        sumy=0
        for p in realm:
            sumx += p[0]
            sumy += p[1]
        avx = sumx / rlen
        avy = sumy / rlen
        diffx = 0
        diffy = 0
        for p in realm:
            diffx += math.fabs(p[0]-avx)
            diffy += math.fabs(p[1]-avy)
        if (math.fabs(pts[i][0]-avx) + math.fabs(pts[i][1]-avy))/(diffx+diffy+0.01)>0.6:
            print("filter out" + str(pts[i])+ "with dist" +str(math.fabs(pts[i][0]-avx) + math.fabs(pts[i][1]-avy)),file=log)
            continue
        res.append(pts[i])
    return res

def filterspeed(pts):
    res = []
    lastp = pts[0]
    res.append(pts[0])
    for i in range(len(pts)):
        if i == 0:
            continue
        thisp = pts[i]
        dist = math.sqrt((thisp[0]-lastp[0])*(thisp[0]-lastp[0]) + (thisp[1]-lastp[1])*(thisp[1]-lastp[1]))
        speed = dist / (thisp[2] - lastp[2])
        if speed<1e-3:
            res.append(thisp)
            lastp = thisp
        else:
            print("filter out" + str(pts[i]) + "with speed" + str(speed))
            print("filter out" + str(pts[i]) + "with speed" + str(speed),file=log)
    return res


